INSERT INTO public.photos VALUES (21818, 'P.‚î¨‚ïë de la Independencia 1930', 'Imagen capturada desde cierta altura, de un sector de la plaza de la Constituci‚îú‚îÇn, y del arranque del antiguo paseo de la Independencia, cuando dec‚îú¬°an que se parec‚îú¬°a a la parisina "rue du Rivoli", sobre todo por su fachada occidental (a la derecha). Una unidad tranviaria de la serie 50 de la l‚îú¬°nea "Torrero", da la vuelta para recomenzar el servicio hacia el sur de la ciudad. Fuente visual: www.delcampe.es', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65134900, -0.88165300, '0101000020E610000000732D5A8036ECBF23A46E675FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31385763036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31385763036.webp', 'https://www.flickr.com/photos/zaragozaantigua/31385763036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21825, 'Pl. de la Constituci‚îú‚îÇn 1930', 'Imagen parcial de la balconada de la antigua Diputaci‚îú‚îÇn Provincial, capturada como muestra de los efectos de la entrada en vigor del Real Decreto que "recuperaba" las diputaciones provinciales, suprimidas durante la dictadura del general Primo de Rivera. Ahora, durante la dictadura del general D‚îú√≠maso Berenguer, buscando remozar el tambaleante r‚îú¬Ægimen que segu‚îú¬°a encabezado por el rey Alfonso XIII, fue derogada la disposici‚îú‚îÇn que derog‚îú‚îÇ las diputaciones. Como consecuencia simb‚îú‚îÇlica, la fotograf‚îú¬°a recoge la nueva presencia compartida de la ense‚îú‚ñía nacional, la bicolor de la izquierda, y la tradicional de la Diputaci‚îú‚îÇn de Zaragoza, la blanca cruzada con asta roja de la derecha. Sobre ambas, el r‚îú‚îÇtulo identificativo de la plaza de la Constituci‚îú‚îÇn, que fue mantenido desde 1923 aunque no hubiera tal. Tras el 18 de julio de 1936, otro gallo negro nos cantar‚îú¬°a. Fuente visual: Miguel Mar‚îú¬°n Chivite, peri‚îú‚îÇdico "Heraldo de Arag‚îú‚îÇn".', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65222100, -0.88155800, '0101000020E61000008FDE701FB935ECBFD8614CFA7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32530850206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32530850206.webp', 'https://www.flickr.com/photos/zaragozaantigua/32530850206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21831, 'P.‚î¨‚ïë de la Independencia 1931', 'Foto: Miguel Mar‚îú¬°n Chivite. Imagen publicada en junio de 1931 del paseo de la Independencia desde la plaza de la Constituci‚îú‚îÇn. Fuente: Heraldo de Arag‚îú‚îÇn.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65202700, -0.88148900, '0101000020E61000006E14596B2835ECBFF38DE89E75D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33363377341.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33363377341.webp', 'https://www.flickr.com/photos/zaragozaantigua/33363377341/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21835, 'Pl. de la Constituci‚îú‚îÇn c.1930', 'Imagen capturada en el antiguo paseo de la Independencia desde el punto de vista de un peat‚îú‚îÇn, con el fondo de la inmediata plaza de la Constituci‚îú‚îÇn y la fachada del Coso. Bien por el efecto de un reciente chaparr‚îú‚îÇn, o un manguerazo, el firme del andador central del paseo, entre acacias, bancos y quioscos, parece reflectante bajo la tibia luz del atardecer. Fuente visual: foto Juan Mora Insa, AMZ.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65179700, -0.88150400, '0101000020E6100000C36169E04735ECBFC25087156ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34119630603.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34119630603.webp', 'https://www.flickr.com/photos/zaragozaantigua/34119630603/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22075, 'P.‚î¨‚ïë de Ruise‚îú‚ñíores c.1955', 'Imagen del exterior del antiguo Colegio Pompiliano de las Escolapias en el Paseo de los Ruise‚îú‚ñíores 28. Se instal‚îú‚îÇ all‚îú¬° en 1922 en un edificio de nueva planta, dedicado a la Segunda Ense‚îú‚ñíanza del "Colegio Calasanz", tambi‚îú¬Æn de las Escolapias. En 1965-68 este Colegio fue objeto de una importante reforma, tanto en su aspecto exterior, como en su estructura, y adquiri‚îú‚îÇ su apariencia actual, despersonalizada, as‚îú¬Æptica. Sigue siendo un colegio privado financiado p‚îú‚ïëblicamente, es decir, concertado.', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63611700, -0.88986000, '0101000020E61000000B98C0ADBB79ECBFFEB627486CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15555677327.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15555677327.webp', 'https://www.flickr.com/photos/zaragozaantigua/15555677327/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21885, 'Plaza de la Constituci‚îú‚îÇn 1936', 'Imagen capturada desde la leve altura de las escaleras de ingreso al antiguo edificio de la Diputaci‚îú‚îÇn Provincial sito en la plaza de la Constituci‚îú‚îÇn, y centrada en los restos de un avi‚îú‚îÇn biplano Vickers Vildebeest de las Fuerzas A‚îú¬Æreas de la Rep‚îú‚ïëblica Espa‚îú‚ñíola exhibido como trofeo de guerra por los nacionalistas sublevados. Aunque originalmente este aeroplano fue destinado a funciones de ataque naval, las necesidades de guerra obligaron a su uso como bombardero de ataque terrestre, en este caso en el frente de Arag‚îú‚îÇn. Al fondo, tramo edilicio del Coso recayente a la plaza entre el inmueble del n‚î¨‚ïë 33 y el n‚î¨‚ïë 39, en la embocadura de la calle de los M‚îú√≠rtires, donde destaca el toldo del Caf‚îú¬Æ Oriental. En los bajos del n‚î¨‚ïë 35 destaca el r‚îú‚îÇtulo del Caf‚îú¬Æ Royalty. La fachada del n‚î¨‚ïë 33 aparece todav‚îú¬°a sin la parafernalia de s‚îú¬°mbolos que lo identificar‚îú¬°an luego como sede provincial de Falange.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65243200, -0.88124500, '0101000020E6100000C16ED8B62833ECBF936E4BE482D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49624253307.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49624253307.webp', 'https://www.flickr.com/photos/zaragozaantigua/49624253307/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21889, 'Plaza de la Constituci‚îú‚îÇn 1936', 'Imagen centrada en los restos de un avi‚îú‚îÇn biplano Vickers Vildebeest de las Fuerzas A‚îú¬Æreas de la Rep‚îú‚ïëblica Espa‚îú‚ñíola exhibido como trofeo de guerra por los nacionalistas sublevados en un acto de propaganda y para elevar la moral de la parroquia que asiste al evento. El fondo esc‚îú¬Ænico viene definido por la decimon‚îú‚îÇnica fachada de la Diputaci‚îú‚îÇn Provincial, a la izquierda, y el inmueble del n‚î¨‚ïë 62-64 del Coso Alto, en cuyos bajos destaca el toldo de la terraza del Caf‚îú¬Æ Gambrinus.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65223200, -0.88144800, '0101000020E6100000CAFCA36FD234ECBFCCB392567CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49685999638.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49685999638.webp', 'https://www.flickr.com/photos/zaragozaantigua/49685999638/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21899, 'Plaza de la Constituci‚îú‚îÇn 1936', 'Desde la altura del estudio de Foto Skogler, vista en la plaza de la Constituci‚îú‚îÇn del desfile organizado con motivo de la celebraci‚îú‚îÇn del tercer aniversario de la fundaci‚îú‚îÇn de Falange en el Teatro de la Comedia de Madrid. Adem‚îú√≠s de falangistas de toda la regi‚îú‚îÇn, acudieron otros varios miles desde Logro‚îú‚ñío hasta alcanzar unos "cincuenta mil hombres, soldados de la nueva Espa‚îú‚ñía que se est‚îú√≠ forjando" (sic). En la imagen abren el desfile unos "flechas", ni‚îú‚ñíos entre 11 y 15 a‚îú‚ñíos de la organizaci‚îú‚îÇn juvenil falangista, que dirigen la marcha hacia el tramo alto del Coso. Al fondo y en el paseo de la Independencia destaca la decimon‚îú‚îÇnica fachada del convento de Jerusal‚îú¬Æn.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65228000, -0.88130900, '0101000020E6100000717495EEAE33ECBFDDEA39E97DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51229924080.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51229924080.webp', 'https://www.flickr.com/photos/zaragozaantigua/51229924080/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21923, 'Plaza de la Constituci‚îú‚îÇn 1936', 'Imagen centrada en los restos del accidentado tren de aterrizaje de un avi‚îú‚îÇn biplano Vickers Vildebeest de las Fuerzas A‚îú¬Æreas de la Rep‚îú‚ïëblica Espa‚îú‚ñíola derribado en Torremocha de Jiloca (Teruel) a finales del mes de julio por los nacionalistas sublevados en armas contra la Rep‚îú‚ïëblica. Posan en la instant‚îú√≠nea elementos de la organizaci‚îú‚îÇn local parapolicial Acci‚îú‚îÇn Ciudadana ante el fondo esc‚îú¬Ænico del inmueble del n‚î¨‚ïë 33 del Coso Alto, que pronto ser‚îú¬°a habilitado como sede provincial de Falange. Este aeroplano fue exhibido en el entorno urbano ante la Diputaci‚îú‚îÇn Provincial como trofeo de guerra y "con este motivo se registraron escenas y manifestaciones de exaltaci‚îú‚îÇn patri‚îú‚îÇtica y vivas entusi‚îú√≠sticos a Espa‚îú‚ñía, al Ej‚îú¬Ærcito espa‚îú‚ñíol y a las milicias movilizadas que colaboraban en este movimiento salvador de la Patria", tal y como se registraba en la prensa de la ‚îú¬Æpoca.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.65256100, -0.88123400, '0101000020E6100000C7F143A51133ECBF91D26C1E87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/55041300276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/55041300276.webp', 'https://www.flickr.com/photos/zaragozaantigua/55041300276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22007, 'Pl. de Espa‚îú‚ñía 1941', 'Imagen capturada junto a los evacuatorios ubicados al principio del andador central del paseo de la Independencia con vista parcial de la plaza de Espa‚îú‚ñía (de la Constituci‚îú‚îÇn antes de julio de 1936) y el arranque de la calle de Don Jaime I (al fondo). De izquierda a derecha, tres esquineras y referenciales entidades bancarias copan la visual: el Banco Zaragozano, el Banco de Espa‚îú‚ñía y el Banco de Vizcaya. Fuente visual: foto Luker, en www.todocoleccion.net', 1941, 1941, 1941, 'Anos 40', 'CENTRO', 41.65170500, -0.88139400, '0101000020E6100000FE7F9C306134ECBFE1D1C6116BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38808957215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38808957215.webp', 'https://www.flickr.com/photos/zaragozaantigua/38808957215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22020, 'Vista c.1940', 'Imagen capturada desde la altura del Centro Mercantil, Industrial y Agr‚îú¬°cola y orientada hacia el noroeste, con vista en primer t‚îú¬Ærmino de la calle de Alfonso I, donde destaca el ‚îú√≠guila que culmina los hom‚îú‚îÇnimos grandes almacenes, a la izquierda. Hacia el fondo y la derecha emergen la torre de la iglesia de San Felipe y Santiago el Menor, el Torre‚îú‚îÇn Fortea y la c‚îú‚ïëpula y torres de la iglesia de Santa Isabel de Portugal.', 1940, 1940, 1940, 'Anos 40', 'CENTRO', 41.65360300, -0.88162000, '0101000020E610000011FC6F253B36ECBFA3C85A43A9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49894909547.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49894909547.webp', 'https://www.flickr.com/photos/zaragozaantigua/49894909547/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22138, 'Plaza Espa‚îú‚ñía 1951', 'Foto: Joan Miquel i Quintilla. Plaza de Espa‚îú‚ñía, con el Monumento a los M‚îú√≠rtires y el inicio del paseo de la Independencia al fondo. Preside la imagen el edificio del Banco Hispano Americano, en el n‚îú‚ïëmero 2 del paseo, obra de Miguel ‚îú√ºngel Navarro de 1916 y remodelado por ‚îú¬Æl mismo en 1940. Fuente: barcelonafotoantic.com/', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65192600, -0.88138500, '0101000020E610000031EBC5504E34ECBFC0B4A84F72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24756570536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24756570536.webp', 'https://www.flickr.com/photos/zaragozaantigua/24756570536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22241, 'P.‚î¨‚ïë de la Independencia 1953', 'Nocturna imagen de la luminosa fachada de la sucursal del Banco de Vizcaya sita en el paseo de la Independencia n‚î¨‚ïë 4. Fundado en 1901, este banco inaugur‚îú‚îÇ sucursal en la ciudad en 1930 justo enfrente a esta ubicaci‚îú‚îÇn. En la imagen, el paseo presenta su tradicional pavimentado de cuando el boulevar central arbolado caracterizaba su aspecto. Entre las piedras del suelo refulgen las v‚îú¬°as del tranv‚îú¬°a. Hacia la izquierda, ingreso a la calle del Requet‚îú¬Æ Aragon‚îú¬Æs. Flechas y yugos y una jaculatoria al Jefe del estado aparecen pintadas en los pilares que soportan los porches del paseo.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65190300, -0.88163100, '0101000020E61000000C7904375236ECBF0795B88E71D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51022538653.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51022538653.webp', 'https://www.flickr.com/photos/zaragozaantigua/51022538653/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22115, 'Marif‚îú¬Æ de Triana 1956', 'Foto: Miguel Mar‚îú¬°n Chivite. La etapa 11 de la Vuelta Ciclista a Espa‚îú‚ñía de 1956 (T‚îú√≠rrega-Zaragoza), celebrada el 6 de mayo de 1956, dio como vencedor al belga Rik Van Steenbergen (abajo). Arriba a la derecha, la cantante Marif‚îú¬Æ de Triana (1936-2013), que actuaba esos d‚îú¬°as en el Teatro Principal, le entrega el ramo de flores de rigor en el lugar de la meta, el parque Primo de Rivera. Fuente: Heraldo de Arag‚îú‚îÇn.', 1956, 1956, 1956, 'Anos 50', 'UNIVERSIDAD', 41.63438400, -0.89427000, '0101000020E6100000CB67791EDC9DECBF868DB27E33D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22339736449.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22339736449.webp', 'https://www.flickr.com/photos/zaragozaantigua/22339736449/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22242, 'Calle de Alfonso I, 1953', 'Imagen centrada en los bajos comerciales que flanquean el ingreso al inmueble del n‚î¨‚ïë 12 de la calle de Alfonso I. As‚îú¬°, a la izquierda, la tienda de Calzados Briz, y a la derecha la sucursal urbana n‚î¨‚ïë 1 del Banco Popular Espa‚îú‚ñíol. Esta entidad hab‚îú¬°a sido fundada en 1926 con el nombre de "Banco Popular de los Previsores del Porvenir", que conserv‚îú‚îÇ hasta que en 1947 adquiri‚îú‚îÇ la denominaci‚îú‚îÇn que luce en la fachada. Sobre ella, el estudio fotogr‚îú√≠fico de los Coyne. En 2017 este banco fue comprado por el Santander al precio de 1 euro, y tras un largo proceso de integraci‚îú‚îÇn operativa, en 2019 desapareci‚îú‚îÇ su marca corporativa.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65337000, -0.88171700, '0101000020E6100000AF78EA910637ECBF0118CFA0A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51024022221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51024022221.webp', 'https://www.flickr.com/photos/zaragozaantigua/51024022221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22474, 'Plaza de San Roque c.1965', 'Imagen a cierta altura, capturada posiblemente desde el Hotel Oriente, del entorno de la plaza de San Roque y el arranque de la calle del Teniente Coronel Valenzuela, donde la amplia zona de aparcamiento en bater‚îú¬°a evidencia la absoluta necesidad, para ese objeto, del ensanche acometido en esta calle en 1942, que supuso, entre otros, el derribo del barroco arco de San Roque. Fuente visual: www.todocoleccion.net/', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65281400, -0.88163300, '0101000020E61000003961C2685636ECBF7B2FBE688FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33860972440.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33860972440.webp', 'https://www.flickr.com/photos/zaragozaantigua/33860972440/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22531, 'Pl. de Espa‚îú‚ñía 1973', 'La plaza de Espa‚îú‚ñía segu‚îú¬°a siendo el centro neur‚îú√≠lgico de la ciudad, si bien a medida que terminaba el siglo esa centralidad se iba desplazando hacia la plaza de Basilio Para‚îú¬°so. En la imagen y al fondo, tramo del Coso entre la calle de los M‚îú√≠rtires y la de Don Jaime I, donde se destacan los grandes anuncios comerciales luminosos establecidos sobre los tejados. El Monumento a los M‚îú√≠rtires de la Religi‚îú‚îÇn y de la Patria, aislado de su entorno, aparece como hito visual referente de la rotonda automovil‚îú¬°stica de la plaza. En primer t‚îú¬Ærmino y a la izquierda, coexistencia pac‚îú¬°fica de dos medios de transporte p‚îú‚ïëblicos: el tranv‚îú¬°a n‚î¨‚ïë 112 de la l‚îú¬°nea 5. Venecia-Delicias, y el autob‚îú‚ïës urbano, en este caso microb‚îú‚ïës de la l‚îú¬°nea Miraflores-Plaza del Pilar, poco antes de que el segundo destronara al primero, con el inestimable fomento pol‚îú¬°tico del Ayuntamiento.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65204800, -0.88133600, '0101000020E6100000D732198EE733ECBF0BB6114F76D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14729125847.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14729125847.webp', 'https://www.flickr.com/photos/zaragozaantigua/14729125847/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22750, 'Pl. de Espa‚îú‚ñía 1972', 'Imagen de la tranviaria composici‚îú‚îÇn M113+R113 de la l‚îú¬°nea 5 "corta" (tras la supresi‚îú‚îÇn del tramo de Delicias) Plaza Espa‚îú‚ñía-Venecia, encaminada hacia el elevado sur de la ciudad. Ni corta, ni perezosa, esta l‚îú¬°nea no llegar‚îú¬°a a ver la Copa Mundial de F‚îú‚ïëtbol celebrada en la Rep‚îú‚ïëblica Federal de Alemania en 1974: las molestias que ocasionaba a la circulaci‚îú‚îÇn rodada parec‚îú¬°an insoportables, como la imagen bien ilustra. Al fondo, la vistosa fachada del Coso con sus comerciales de ne‚îú‚îÇn. Fuente visual: www.flickr.com/photos/jhm0284/5812528283/in/album-7215763...', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.65199800, -0.88132100, '0101000020E610000082E50819C833ECBF5987A3AB74D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32594356565.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32594356565.webp', 'https://www.flickr.com/photos/zaragozaantigua/32594356565/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23072, 'Coso 2007', 'Fuente: Wikipedia, 2007. Aspecto del tramo del Coso Alto con el palacio de S‚îú√≠stago y la densa circulaci‚îú‚îÇn rodada anterior a la implantaci‚îú‚îÇn del tranv‚îú¬°a en 2011.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.65276800, -0.88167600, '0101000020E61000000B613596B036ECBF0BF0DDE68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15012274978.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15012274978.webp', 'https://www.flickr.com/photos/zaragozaantigua/15012274978/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23094, 'Palacio de S‚îú√≠stago 2000', 'Aspecto de la fachada sur del palacio de S‚îú√≠stago de Zaragoza, antes de su restauraci‚îú‚îÇn entre 2001 y 2003. Actualmente esta ubicaci‚îú‚îÇn es un patio interior de la Diputaci‚îú‚îÇn Provincial de Zaragoza. La hilera de ventanas superior alberga las dependencias de la Instituci‚îú‚îÇn Fernando el Cat‚îú‚îÇlico. Fuente: "Restauraci‚îú‚îÇn del patrimonio hist‚îú‚îÇrico en la provincia de Zaragoza", Diputaci‚îú‚îÇn de Zaragoza, 2003.', 2000, 2000, 2000, 'Siglo XXI', 'CENTRO', 41.65247300, -0.88168500, '0101000020E6100000D8F50B76C336ECBFF2423A3C84D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21500598541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21500598541.webp', 'https://www.flickr.com/photos/zaragozaantigua/21500598541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23131, 'Coso alto 2004', 'En 1967 fue fundada la Caja Rural Comarcal de Calatayud, en esa localidad, por Salvador Ibarra Franco. En 1970 la entidad cambi‚îú‚îÇ su denominaci‚îú‚îÇn por Caja Rural del Jal‚îú‚îÇn ("Cajal‚îú‚îÇn") Sociedad Cooperativa de Credito, y en 1979 traslad‚îú‚îÇ su sede social a Zaragoza, en el paseo de la Independencia n‚î¨‚ïë 25. En 2004, y tras dos a‚îú‚ñíos de costosa rehabilitaci‚îú‚îÇn integral, inaugur‚îú‚îÇ su nueva sede en el antiguo inmueble del Casino Mercantil, en el n‚î¨‚ïë 29 del Coso. Durante los actos de presentaci‚îú‚îÇn de la flamante sede, desde la entidad se dijo que con ello "Nos vestimos de largo, es nuestra mayor‚îú¬°a de edad tras haber adecuado previamente la estructura interna". En 2011, tras el proceso de fusi‚îú‚îÇn con Multicaja, Cajal‚îú‚îÇn se integr‚îú‚îÇ en la Nueva Caja Rural de Arag‚îú‚îÇn Sociedad Cooperativa de Cr‚îú¬Ædito, que desde enero de 2012 opera bajo la denominaci‚îú‚îÇn Bantierra Cooperativa de Credito. En la imagen, fachada del n‚î¨‚ïë 29 del Coso alto, como nueva sede central de Cajal‚îú‚îÇn. En primer plano, el Coso como coto vedado para uso de la circulaci‚îú‚îÇn rodada. Fuente visual: es.wikipedia.org', 2004, 2004, 2004, 'Siglo XXI', 'CENTRO', 41.65270400, -0.88132100, '0101000020E610000082E50819C833ECBFF4FBFECD8BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31636805394.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31636805394.webp', 'https://www.flickr.com/photos/zaragozaantigua/31636805394/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23278, 'Calle de Alfonso I 1889', 'J. L‚îú¬Ævy et Cie, 1889', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65347000, -0.88179300, '0101000020E610000070EF1AF4A537ECBF6475ABE7A4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14804609167.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14804609167.webp', 'https://www.flickr.com/photos/zaragozaantigua/14804609167/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23292, 'Calle de Alfonso I c.1964', 'Foto: Ediciones Sicilia. Imagen nocturna de la Calle Alfonso I de Zaragoza engalanada. Fuente: rafaelcastillejo.com', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65360200, -0.88171800, '0101000020E6100000C66CC9AA0837ECBFD34CF73AA9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20523509138.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20523509138.webp', 'https://www.flickr.com/photos/zaragozaantigua/20523509138/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23293, 'Calle de Alfonso I 1958', 'Foto: Ediciones Sicilia. Colecci‚îú‚îÇn de ‚îú√ºngel Ruiz. Vista nocturna de la calle Alfonso I de Zaragoza en octubre de 1958. Fuente: rafaelcastillejo.com', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.65360200, -0.88171800, '0101000020E6100000C66CC9AA0837ECBFD34CF73AA9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20685122166.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20685122166.webp', 'https://www.flickr.com/photos/zaragozaantigua/20685122166/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23294, 'Calle de Alfonso I 1908', 'Paso de la comparsa de gigantes y cabezudos en direcci‚îú‚îÇn hacia el Coso Alto, a la altura de la calle del Cuatro de Agosto. El engalanamiento es debido a las celebraciones del centenario de los sitios. Fuente visual: Archivo Julio Requejo (DARA-AHPZ).', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.65360200, -0.88171800, '0101000020E6100000C66CC9AA0837ECBFD34CF73AA9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21092411081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21092411081.webp', 'https://www.flickr.com/photos/zaragozaantigua/21092411081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23297, 'Calle de Alfonso I c.1900', 'Postal editada por la "Fototipia Hauser y Menet" (Madrid), con imagen de la calle Alfonso I en el turno de paseo de "no elegantes" de clase baja. Un veh‚îú¬°culo a propulsi‚îú‚îÇn de sangre, estacionado sin complejos. A la derecha, el entronque con la calle del Cuatro de Agosto. Fuente visual: www.delcampe.net/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.65351700, -0.88169400, '0101000020E6100000A48AE255D636ECBFA530EF71A6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22845537949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22845537949.webp', 'https://www.flickr.com/photos/zaragozaantigua/22845537949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22213, 'Parque Grande 1955', 'Imagen capturada desde la altura del Cabezo de Buenavista y orientada hacia el ingreso al Parque de Primo de Rivera desde el puente del Trece de Septiembre. Centran la imagen, entre la foresta, las instalaciones del Jard‚îú¬°n Bot‚îú√≠nico. A la izquierda, emerge el destacado volumen de la Residencia Sanitaria Jos‚îú¬Æ Antonio. A su lado y hacia el fondo, el despejado panorama de torres agr‚îú¬°colas entre el Pol‚îú¬°gono Gran V‚îú¬°a y la carretera de Valencia. A la derecha, la torre de la Feria de Muestras y el cuartel de Palafox, tras el que la vista todav‚îú¬°a alcanza hasta los pabellones del Hospital Psiqui‚îú√≠trico Nuestra Se‚îú‚ñíora del Pilar. Fuente visual: AMZ', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.63548000, -0.89649900, '0101000020E6100000CDB1BCAB1EB0ECBF8CA19C6857D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46027854615.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46027854615.webp', 'https://www.flickr.com/photos/zaragozaantigua/46027854615/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23301, 'Calle del Blas‚îú‚îÇn Aragon‚îú¬Æs 1966', 'Imagen capturada desde el cruce de la calle del Cuatro de Agosto (de izquierda a derecha) con la antigua calle del Peso, luego redenominada "Blas‚îú‚îÇn Aragon‚îú¬Æs", que conduce, al fondo, a la antigua plaza del Carb‚îú‚îÇn, luego de Sas. La calle del Peso, hac‚îú¬°a referencia a la ubicaci‚îú‚îÇn del "Peso del Rey" utilizado para la distribuci‚îú‚îÇn al por menor del carb‚îú‚îÇn vegetal como elemento imprescindible para los hogares, como combustible para la cocina, y para proporcionar calor al hogar en invierno. En la manzana de la derecha, entre la calle del Cuatro de Agosto, y Est‚îú¬Æbanes, se abre el denominado "Pasaje de los Giles", nombre dado en el siglo XIX al enorme espacio compuesto desde el siglo XVI por el patio de la Casa de los Est‚îú¬Æbanes, por una galer‚îú¬°a, y un patio posterior ajardinado en las traseras de la casa. Este espacio fue muy reformado en el siglo XIX por sus nuevos propietarios, los comerciantes y hermanos Garc‚îú¬°a Gil, con intervenciones dise‚îú‚ñíadas por Julio Bravo, y Ricardo Magdalena. En los a‚îú‚ñíos 50 del pasado siglo, Teodoro R‚îú¬°os consolida la cimentaci‚îú‚îÇn. A comienzos del presente siglo XXI, ha sido "rehabilitado" integralmente. En la imagen, en la acera de los pares de la calle Blas‚îú‚îÇn Aragon‚îú¬Æs, andamios que anuncian el principio del fin de la esquinera casona palaciega de los barones de La Linde, y su sustituci‚îú‚îÇn por nuevos y modernos edificios m‚îú√≠s acordes a los tiempos. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65339700, -0.88125400, '0101000020E61000008E03AF963B33ECBFFA264D83A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24131226424.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24131226424.webp', 'https://www.flickr.com/photos/zaragozaantigua/24131226424/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23307, 'Calle de Alfonso I 1874', 'Vista de la calle de Alfonso I. Fuente: Anselmo Mar‚îú¬°a Coyne Barreras, probable copia de imagen de Mariano J‚îú‚ïëdez y Ortiz. Colecci‚îú‚îÇn Antonio Arguas Perdiguer. Libro Primeros tiempos de la fotograf‚îú¬°a en Zaragoza.', 1874, 1874, 1874, 'Siglo XIX', 'CENTRO', 41.65351700, -0.88169400, '0101000020E6100000A48AE255D636ECBFA530EF71A6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28553354656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28553354656.webp', 'https://www.flickr.com/photos/zaragozaantigua/28553354656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23502, 'Coso Alto 1930', '"Calle del Coso". A la izquierda, el Palacio de S‚îú√≠stago y el edificio del antiguo Banco de Arag‚îú‚îÇn. A la derecha, la entrada a la calle Alfonso. Al fondo, el chafl‚îú√≠n de Escolapios.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65278500, -0.88156700, '0101000020E61000005C7347FFCB35ECBFE12879758ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15061161651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15061161651.webp', 'https://www.flickr.com/photos/zaragozaantigua/15061161651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23505, 'Casino Mercantil 1937', 'El s‚îú√≠bado 30 de enero de 1937 tuvo lugar "una fiesta brillante" en el Centro Mercantil, Industrial y Agr‚îú¬°cola de la ciudad. La Colonia Alemana y la organizaci‚îú‚îÇn local del NSDAP (National Sozialistische Deutsche Arbeiterpartei, Partido Nacionalsocialista Alem‚îú√≠n de los Trabajadores) prepararon la conmemoraci‚îú‚îÇn del aniversario 4 del ascenso al poder de Adolf Hitler como su "Fuhrer". El "Sal‚îú‚îÇn Restaurant" del Centro fue engalanado al efecto con profusi‚îú‚îÇn de banderas nacionalistas, y una tribuna especial para los discursos, con un retrato de Hitler, la sv‚îú√≠stica, flores, y un atril. Hubo una "concurrencia numeros‚îú¬°sima", entre la que destacaba el vicepresidente de la DPZ (sr. Mola), un representante del Ayuntamiento (sr. Julve), dos representantes de Falange (sres. M‚îú‚ïëgica, y Gil Sastre), el c‚îú‚îÇnsul italiano en la ciudad (sr. Ricardo Piccio), y las directivas de la Colonia Alemana, y del NSDAP local. Hubo discursos por parte del Sr. Julve, del Sr. Piccio, y del jefe local del NSDAP, sr. Fleischmann, que loaron a Espa‚îú‚ñía, Portugal, Italia, Alemania, y el Jap‚îú‚îÇn, y exaltaron a Adolfo Hitler como "caudillo sin ejemplo en la historia del mundo". Hubo aplausos, recuerdo a sus muertos, saludos fascistas, himnos nacionalistas, y desfile de banderas. Las cr‚îú‚îÇnicas no lo reflejan, pero algo de beber y de comer habr‚îú¬°a. Al terminar el acto, la Colonia Alemana agradeci‚îú‚îÇ a la direcci‚îú‚îÇn del Centro Mercantil la cesi‚îú‚îÇn del local. En la imagen, el jefe local en Zaragoza del NSDAP, sr. Fleischmann, durante su intervenci‚îú‚îÇn, detr‚îú√≠s de Hitler y la sv‚îú√≠stica, y delante de los portaestandartes con las ense‚îú‚ñías de la Alemania nazi, la Espa‚îú‚ñía franquista, la Italia fascista, y de Falange. 14 a‚îú‚ñíos antes, un tal Albert Einstein estuvo en la ciudad, muy cerca del lugar de autos. Era otro tipo de alem‚îú√≠n, que cumpl‚îú¬°a tambi‚îú¬Æn 4 a‚îú‚ñíos, pero de exilio.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65295400, -0.88154500, '0101000020E610000068791EDC9D35ECBF6DE525FF93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15893988667.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15893988667.webp', 'https://www.flickr.com/photos/zaragozaantigua/15893988667/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23509, 'Coso Alto 1889', 'Saragosse. Rue del Coso. J. L‚îú¬Ævy et Cie, 1889. Vista del Coso Alto desde la plaza de la Constituci‚îú‚îÇn de Zaragoza. En la d‚îú¬Æcada de los sesenta del siglo XIX, la transformaci‚îú‚îÇn del antiguo Trenque de Ximeno Gordo, luego calle del Trenque, en la nueva "calle de Don Alfonso I" supuso, entre otras cosas, la obligada renumeraci‚îú‚îÇn de los azulejos del Coso, y la adecuaci‚îú‚îÇn de los edificios esquineros. Con esta monumental imagen nos podemos acercar al estado de los edificios entre la nueva calle Alfonso, y la plaza de la Constituci‚îú‚îÇn, en sus n‚îú‚ïëmeros impares (los de la derecha). As‚îú¬°, la Casa de Eusebio Molins, remodelada luego en formas modernistas; una casa de alquiler donde residi‚îú‚îÇ Francisco de Goya en 1780-81; la vecina casa de Mart‚îú¬°n Zapater (‚îú¬°ntimo de Goya), con andamios para adecuarla, entre otras cosas, a importante tienda de telas; la antigua Casa de Juan Coloma, antes de ser convertida en Centro Mercantil, Industrial y Agr‚îú¬°cola; la casa de los marqueses de Nibbiano, con andamios altos para remodelarla en profundidad y darle una mano de decoraci‚îú‚îÇn historicista que perdurar‚îú√≠ hasta que acabe en manos del Banco de Bilbao; inmediata, otra casa de los Nibbiano que fue pasando de manos en manos hasta recaer en 1936 como sede provincial de la Falange, y en los a‚îú‚ñíos cincuenta terminar como propiedad del Banco Vitalicio de Espa‚îú‚ñía. Fuente visual: Zaragoza en la mirada ajena. Cortes de Arag‚îú‚îÇn, 2012', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.65267200, -0.88129900, '0101000020E61000008EEBDFF59933ECBFE9818FC18AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18614224408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18614224408.webp', 'https://www.flickr.com/photos/zaragozaantigua/18614224408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23515, 'Coso Alto 2011', 'Foto: Oliver Duch. Imagen testigo de la llegada de los ra‚îú¬°les del tranv‚îú¬°a en septiembre de 2011, durante las obras de la segunda fase de la l‚îú¬°nea 1, en su recorrido por el Coso Alto. Al fondo, la plaza de Espa‚îú‚ñía. Fuente: Heraldo de Arag‚îú‚îÇn.', 2011, 2011, 2011, 'Siglo XXI', 'CENTRO', 41.65276600, -0.88151300, '0101000020E610000090F63FC05A35ECBF6AF816D68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26562082199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26562082199.webp', 'https://www.flickr.com/photos/zaragozaantigua/26562082199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23516, 'Coso Alto 1861', 'Vista de la calle del Coso en su tramo Alto, tomada desde la plaza de la Constituci‚îú‚îÇn. Fuente: Mariano J‚îú‚ïëdez y Ortiz. ‚îú√ºlbum de Andr‚îú¬Æs Mart‚îú¬°n e Ip‚îú√≠s. Colecci‚îú‚îÇn Mariano Mart‚îú¬°n Casalderrey. Libro Primeros tiempos de la fotograf‚îú¬°a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.65276800, -0.88167600, '0101000020E61000000B613596B036ECBF0BF0DDE68DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28504316721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28504316721.webp', 'https://www.flickr.com/photos/zaragozaantigua/28504316721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23524, 'Coso Alto 2012', '"Iris del Coso Alto", ‚îú‚îÇleo sobre lienzo, Eduardo Laborda, 2012. La compa‚îú‚ñíera del pintor, Iris L‚îú√≠zaro, aparece a la derecha en el Casino Mercantil, frente al palacio de S‚îú√≠stago. M‚îú√≠s all‚îú√≠, las sucesivas sedes del Banco de Arag‚îú‚îÇn y el edificio La Adri‚îú√≠tica. Sobre el firme, obras de la segunda fase de la l‚îú¬°nea 1 del tranv‚îú¬°a. Fuente: Heraldo de Arag‚îú‚îÇn.', 2012, 2012, 2012, 'Siglo XXI', 'CENTRO', 41.65275800, -0.88152400, '0101000020E61000008A73D4D17135ECBFE719FB928DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39160609620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39160609620.webp', 'https://www.flickr.com/photos/zaragozaantigua/39160609620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23531, 'Centro Mercantil 1937', 'Imagen capturada en el sal‚îú‚îÇn-comedor del Centro Mercantil, Industrial y Agr‚îú¬°cola en el Coso durante la conmemoraci‚îú‚îÇn del cuarto aniversario de la "toma del poder por el Fuhrer Adolfo Hitler" (30 de enero de 1933), acto organizado por el grupo local del "Partido Obrero Nacional-Socialista Alem‚îú√≠n" (NSDAP). Centra la escena la tribuna levantada al fondo del comedor y decorada con profusi‚îú‚îÇn de motivos vegetales, la esv‚îú√≠stica y un retrato del "Fuhrer", durante la intervenci‚îú‚îÇn del jefe local del NSDAP, se‚îú‚ñíor Fleischmann uniformado con la preceptiva camisa parda. El testero de la tribuna presenta una gran bandera con la cruz gamada ante la que forman portaestandartes con las banderas nacionalista espa‚îú‚ñíola, de Falange, la italiana y la alemana. Entre las autoridades asistentes destac‚îú‚îÇ el gestor municipal Julve en representaci‚îú‚îÇn del alcalde; los diputados provinciales Rivas y Mola; el jefe de la Segunda l‚îú¬°nea de Falange, M‚îú‚ïëgica ; los c‚îú‚îÇnsules de Italia y Portugal; toda la colonia alemana y una representaci‚îú‚îÇn de la colonia italiana. Hubo discursos de Julve, del c‚îú‚îÇnsul italiano, representantes de la colonia alemana y del NSDAP, Fleischmann, que loaron a Espa‚îú‚ñía, Portugal, Italia, Alemania y aun el Jap‚îú‚îÇn, exaltaron a Adolfo Hitler como "caudillo sin ejemplo en la historia del mundo", y auguraron un destino paralelo entre Alemania y Espa‚îú‚ñía: "el de su gloria y su grandeza". Adem‚îú√≠s hubo "poes‚îú¬°as y cantos de car‚îú√≠cter patri‚îú‚îÇtico"; una orquesta interpret‚îú‚îÇ piezas de Beethoven y Wagner, adem‚îú√≠s de los himnos alem‚îú√≠n e italiano y el de Falange; aplausos, recuerdo a sus muertos, saludos fascistas, desfile de banderas, despedida y cierre.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65304200, -0.88130900, '0101000020E6100000717495EEAE33ECBF0C7558E196D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51715700660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51715700660.webp', 'https://www.flickr.com/photos/zaragozaantigua/51715700660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22423, 'Parque Primo de RIvera c.1968', 'Fuentes del paseo de San Sebasti‚îú√≠n del parque Primo de Rivera. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.63543000, -0.89545700, '0101000020E61000003C2D3F7095A7ECBFDA722EC555D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27320115622.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27320115622.webp', 'https://www.flickr.com/photos/zaragozaantigua/27320115622/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24358, 'San Juan de los Panetes 1933', 'Archivo ABC. "Incendio de la iglesia de San Juan de los Panetes (Zaragoza) el 19 de diciembre de 1933. Poco antes hab‚îú¬°a sido declarado monumento nacional."', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65753200, -0.88120800, '0101000020E610000078279F1EDB32ECBF680932022AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14977800452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14977800452.webp', 'https://www.flickr.com/photos/zaragozaantigua/14977800452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23532, 'Coso Alto 2005', 'Imagen capturada el 8 de noviembre de 2005 durante la presentaci‚îú‚îÇn en Zaragoza de "El vano ayer", novela ganadora de la decimocuarta edici‚îú‚îÇn del premio literario hispanoamericano "R‚îú‚îÇmulo Gallegos" el a‚îú‚ñío 2005. Centra la escena el sevillano Isaac Rosa Camacho, autor de la novela, flanqueado a nuestra derecha por el historiador Javier Rodrigo S‚îú√≠nchez, que ese mismo a‚îú‚ñío vio publicado su trabajo titulado "Cautivos. Campos de concentraci‚îú‚îÇn en la Espa‚îú‚ñía franquista (1936-1947)"; y a nuestra izquierda por el tambi‚îú¬Æn historiador Manuel Ballar‚îú¬°n Aured, que en 2004 vio publicado su trabajo "La raz‚îú‚îÇn en marcha. Cr‚îú‚îÇnica del Frente Popular de Zaragoza". La novela presentada, "una dur‚îú¬°sima requisitoria al franquismo, a la brutalidad de su sistema policial, a la corrupci‚îú‚îÇn moral que implant‚îú‚îÇ en el pa‚îú¬°s", ven‚îú¬°a acompa‚îú‚ñíada de cierta pol‚îú¬Æmica sensacionalista a cuenta de que el jurado de este premio ten‚îú¬°a connotaciones "bolivarianas" y "chavistas", y a que al autor "se le hab‚îú¬°a o‚îú¬°do hablar a favor de la Revoluci‚îú‚îÇn Cubana acompa‚îú‚ñíado sospechosamente de castristas". Casualmente, esta presentaci‚îú‚îÇn tuvo como escenario la FNAC de Zaragoza, que en los a‚îú‚ñíos treinta del pasado siglo XX era una horchater‚îú¬°a propiedad de Mas que tras el 18-19 de julio de 1936 vio c‚îú‚îÇmo el piso situado sobre ella se convert‚îú¬°a en una "checa" u "oficina de investigaci‚îú‚îÇn" de sospechosos de no simpatizar con la sedici‚îú‚îÇn armada contra la Rep‚îú‚ïëblica espa‚îú‚ñíola.', 2005, 2005, 2005, 'Siglo XXI', 'CENTRO', 41.65300200, -0.88176000, '0101000020E610000081785DBF6037ECBF7E1CCD9195D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52748029423.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52748029423.webp', 'https://www.flickr.com/photos/zaragozaantigua/52748029423/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23988, '14 de abril de 1931', 'Plaza de la Constituci‚îú‚îÇn de Zaragoza, martes 14 de abril de 1931. Proclamaci‚îú‚îÇn de la Segunda Rep‚îú‚ïëblica espa‚îú‚ñíola y celebraci‚îú‚îÇn consiguiente. Al fondo a la derecha, la Diputaci‚îú‚îÇn Provincial. Fuente: Heraldo de Arag‚îú‚îÇn.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65202200, -0.88126700, '0101000020E6100000B66801DA5633ECBFE222F77475D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15858894161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15858894161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15858894161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24001, 'Pl. de la Constituci‚îú‚îÇn 1931', 'Imagen capturada durante la callejera celebraci‚îú‚îÇn ciudadana de la llegada de la Segunda Rep‚îú‚ïëblica, en la plaza de la Constituci‚îú‚îÇn, un luminoso 14 de abril. Animoso grupo de trabajadoras del corte y confecci‚îú‚îÇn, en primera l‚îú¬°nea celebrativa. Al fondo, el clasicista edificio de la Diputaci‚îú‚îÇn Provincial inaugurado en 1858, con su caracter‚îú¬°stico remate en semicircular front‚îú‚îÇn. Fuente visual: Foto Mart‚îú¬°nez ("Mundo Gr‚îú√≠fico", Madrid).', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65220700, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF739CDB847BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21881708770.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21881708770.webp', 'https://www.flickr.com/photos/zaragozaantigua/21881708770/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24004, 'P.‚î¨‚ïë de la Independencia 1975', '‚î¨¬ΩEspa‚îú‚ñíoles... Franco ha muerto. El hombre de excepci‚îú‚îÇn que ante Dios y ante la Historia asumi‚îú‚îÇ la inmensa responsabilidad del m‚îú√≠s exigente y sacrificado servicio a Espa‚îú‚ñía ha entregado su vida, quemada d‚îú¬°a a d‚îú¬°a, hora a hora, en el cumplimiento de una misi‚îú‚îÇn trascendental. Yo s‚îú¬Æ que en estos momentos mi voz llegar‚îú√≠ a vuestros hogares entrecortada y confundida por el murmullo de vuestros sollozos y de vuestras plegarias. Es natural; es el llanto de Espa‚îú‚ñía, que siente como nunca la angustia infinita de su orfandad. Es la hora del dolor y de la tristeza...‚î¨‚ïó (Principio de la compungida y peripat‚îú¬Ætica intervenci‚îú‚îÇn televisiva de Carlos Arias Navarro, Presidente del Gobierno, anunciando la muerte del Jefe del Estado, el 20-N-1975). Inmediatamente, fueron suspendidos todos los dem‚îú√≠s espect‚îú√≠culos p‚îú‚ïëblicos hasta el domingo siguiente, d‚îú¬°a 23. Con este, suficiente. Las clases (escolares) quedaron suspendidas una semana, hasta el d‚îú¬°a 27. Una bendici‚îú‚îÇn para las familias. La capilla ardiente del finado fue encendida en el Palacio de Oriente al d‚îú¬°a siguiente, d‚îú¬°a 21. Dos d‚îú¬°as despu‚îú¬Æs, el s‚îú√≠bado 22, fue proclamado sucesor como Jefe del Estado el delf‚îú¬°n Juan Carlos de Borb‚îú‚îÇn. El domingo 23, Franco fue inhumado en el "Valle de los Ca‚îú¬°dos". En la imagen, lectura de la muerte de Franco recogida en el local diario "El Noticiero", en los porches del paseo de la Independencia, en la primera de las varias ediciones de ese d‚îú¬°a que vivimos peligrosamente.', 1975, 1975, 1975, 'Anos 70', 'CENTRO', 41.65171000, -0.88170700, '0101000020E6100000CCEF3499F136ECBFF33CB83B6BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23545954464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23545954464.webp', 'https://www.flickr.com/photos/zaragozaantigua/23545954464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24929, 'Piscina Parque Grande 1968', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/julio 1968. Desde mediados de los a‚îú‚ñíos 60, varios parques de la ciudad fueron dotados de piscinas para la chavaler‚îú¬°a. T‚îú¬°o Jorge, Bruil, y Parque Grande a‚îú‚ñíad‚îú¬°an en verano el atractivo del agua y la diversi‚îú‚îÇn bajo la can‚îú¬°cula, que en Zaragoza no es cualquier cosa. No ten‚îú¬°an recinto que las delimitara, estaban abiertas a todo el mundo, y sol‚îú¬°an llenarse hasta parecer pobladas por piojos mojados. Pero era lo que hab‚îú¬°a. Ya en los a‚îú‚ñíos 80, la nuevas pol‚îú¬°ticas municipales asumieron constituir una red de piscinas municipales en los barrios, incluyendo los rurales, que alcanzan la cifra de 22. Aquellas viejas piscinas sesenteras fueron clausuradas por motivos de salubridad y seguridad. La imagen recoge la piscina del Parque Grande, ubicada justo entre el r‚îú¬°o Huerva y el actual Paseo de los Pl‚îú√≠tanos, del que se pod‚îú¬°a acceder por la rampa de la imagen, al fondo, a la derecha.', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.63214300, -0.89796800, '0101000020E61000004B581B6327BCECBF9AB2D30FEAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14859093063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14859093063.webp', 'https://www.flickr.com/photos/zaragozaantigua/14859093063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24013, 'Pl. de Espa‚îú‚ñía 1966', 'El obligatorio Refer‚îú¬Ændum (hab‚îú¬°a que firmar certificados de participaci‚îú‚îÇn) celebrado el 14 de diciembre de 1966, somet‚îú¬°a a sufragio la "Ley Org‚îú√≠nica del Estado", apenas unos leves retoques cosm‚îú¬Æticos de algunas instituciones del R‚îú¬Ægimen, pero eran tan buenos y populares que recibieron el 95,06% de votos favorables. El 4,94% restante, entre votos nulos, y negativos. El refer‚îú¬Ændum fue antecedido de una campa‚îú‚ñía de propaganda donde se identificaba el "S‚îú¬°" con "un futuro de paz y progreso", con "patria, progreso, justicia, pan, bienestar, seguridad, porvenir, desarrollo y paz". El "S‚îú¬°" era tambi‚îú¬Æn un "S‚îú¬° a Franco", porque "Franco triunf‚îú‚îÇ en el pasado, asegura el presente, y promete el futuro". Como los menores de 21 a‚îú‚ñíos no ten‚îú¬°an derecho a votar, se recomendaba que, ya que "Tus hijos menores no votan, T‚îú‚ïë, s‚îú¬°. Aseg‚îú‚ïërales un futuro de paz y de progreso en el refer‚îú¬Ændum nacional". Un peculiar y castizo fen‚îú‚îÇmeno de democracia, progreso y participaci‚îú‚îÇn, tan singular como los arcoiris de Plut‚îú‚îÇn. En la imagen, vista de la plaza de Espa‚îú‚ñía en las inmediaciones a las urnas de la Diputaci‚îú‚îÇn Provincial, con nutridas filas de ardorosos y concienciados participantes en el refer‚îú¬Ændum, porque ‚î¨‚îêqui‚îú¬Æn no se atrever‚îú¬°a a votar por el bienestar de sus hijos, y el de Franco mismo? Entre las pel‚îú¬°culas del momento, en la cartelera de la ciudad, "Divorcio a la italiana", porque a la espa‚îú‚ñíola, imposible.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65220700, -0.88149200, '0101000020E6100000B3F0F5B52E35ECBF739CDB847BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24189394985.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24189394985.webp', 'https://www.flickr.com/photos/zaragozaantigua/24189394985/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24015, 'P.‚î¨‚ïë de la Independencia 2003', 'La convocatoria de manifestaciones contra la invasi‚îú‚îÇn de Irak por parte de los Estados Unidos se considera la primera movilizaci‚îú‚îÇn global de la historia. Las m‚îú√≠s numerosas se produjeron el 15 de febrero de 2003, con el lema de "‚î¨√≠No a la guerra!". Un ejemplo es la de Zaragoza, que congreg‚îú‚îÇ a una muchedumbre en el paseo de la Independencia y aleda‚îú‚ñíos. El 20 de marzo de 2003 comenz‚îú‚îÇ, sin embargo, la invasi‚îú‚îÇn prevista, con el apoyo del Gobierno de Espa‚îú‚ñía. Fuente: Agencia EFE.', 2003, 2003, 2003, 'Siglo XXI', 'CENTRO', 41.65174600, -0.88174200, '0101000020E6100000E84EB0FF3A37ECBF40A6B5696CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24303954079.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24303954079.webp', 'https://www.flickr.com/photos/zaragozaantigua/24303954079/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24049, 'Pl. de la Constituci‚îú‚îÇn 1931', 'Aspecto de la plaza de la Constituci‚îú‚îÇn, con la Diputaci‚îú‚îÇn Provincial al fondo, durante las celebraciones de la tarde del 14 de abril de 1931, d‚îú¬°a de la proclamaci‚îú‚îÇn de la Segunda Rep‚îú‚ïëblica. Fuente: Heraldo de Arag‚îú‚îÇn.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65210100, -0.88122500, '0101000020E6100000FB5C6DC5FE32ECBF2E58AA0B78D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31125852943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31125852943.webp', 'https://www.flickr.com/photos/zaragozaantigua/31125852943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24063, 'Plaza de Espa‚îú‚ñía 1966', 'Como anuncia el cartel‚îú‚îÇn del Argensola, "A reir tocan". En primer t‚îú¬Ærmino, exultantes mozos celebran haber sido sorteados para el servicio militar obligatorio, con sonoro acompa‚îú‚ñíamiento musical de guitarra y palmas, y alcohol de literal garraf‚îú‚îÇn. A la derecha, carteles con algunos candidatos a las "elecciones" municipales por el tercio de representantes sindicales celebradas con notable ‚îú¬Æxito de participaci‚îú‚îÇn (algo m‚îú√≠s del 30%), siendo electos los se‚îú‚ñíores Emilio Parra Gasque, Joaqu‚îú¬°n Liarte Alpuente, Jos‚îú¬Æ Rodrigo Liarte, y Alfonso Sol‚îú√≠ns Serrano. Paul Newman, caracterizado como "Harper", ojipl‚îú√≠tico ante el panorama. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65196100, -0.88140400, '0101000020E6100000E10852297634ECBF3CA2427573D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32796513701.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32796513701.webp', 'https://www.flickr.com/photos/zaragozaantigua/32796513701/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24065, 'Fiesta del Trabajo 1931', 'El primer 1 de mayo desde la proclamaci‚îú‚îÇn de la Segunda Rep‚îú‚ïëblica fue celebrado a lo grande en Zaragoza, con una manifestaci‚îú‚îÇn que discurri‚îú‚îÇ entre la plaza de la Libertad y el Gobierno Civil y cont‚îú‚îÇ con la asistencia calculada por la prensa de la ‚îú¬Æpoca en unas 30.000 personas y que por ello fue considerada la m‚îú√≠s numerosa de aquellos tiempos. En la imagen del paseo de la Independencia la captura fotogr‚îú√≠fica se centra en el cortejo encabezado con la pancarta de la Agrupaci‚îú‚îÇn Socialista de Zaragoza, donde destaca el s‚îú¬°mbolo del PSOE del yunque y la pluma. Al fondo, plaza de la Constituci‚îú‚îÇn.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65158000, -0.88152600, '0101000020E6100000B85B92037635ECBF255D33F966D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33106148790.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33106148790.webp', 'https://www.flickr.com/photos/zaragozaantigua/33106148790/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24100, 'Plaza de Espa‚îú‚ñía c.1937', 'Ins‚îú‚îÇlita imagen capturada en la nueva plaza de Espa‚îú‚ñía cuando se‚îú‚ñíoras y se‚îú‚ñíoritas procesionando desde el Coso Alto ingresan a ella ante la sede provincial de Falange Espa‚îú‚ñíola de las JONS portando banderas nacionalistas y una pancarta entusiasta con el partido ‚îú‚ïënico. Al fondo y a la izquierda, el inmueble del n‚î¨‚ïë 31 del Coso, que entre otros negocios acog‚îú¬°a a la sede central del Banco de Bilbao, la compa‚îú‚ñí‚îú¬°a aseguradora La Patria Hispana, y el estudio fotogr‚îú√≠fico "Skogler" regentado por ‚îú√ºngel Cort‚îú¬Æs Gracia, que en la imagen aparece con camisa blanca asomado a la izquierda del balc‚îú‚îÇn. A la derecha, el inmueble del n‚î¨‚ïë 33 que, propiedad del Banco Vitalicio, acog‚îú¬°a la sede de Falange, adem‚îú√≠s de la joyer‚îú¬°a de A. Agueras y el despacho del corredor de comercio S. Hern‚îú√≠ndez.', 1937, 1937, 1937, 'Anos 30', 'CENTRO', 41.65256100, -0.88123400, '0101000020E6100000C7F143A51133ECBF91D26C1E87D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51175302112.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51175302112.webp', 'https://www.flickr.com/photos/zaragozaantigua/51175302112/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
